import React, { useState, useEffect, useMemo, useCallback } from "react";
import axios from "axios";

import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend,
  LineElement,
  CategoryScale,
  LinearScale,
  PointElement
} from "chart.js";

import { Pie, Line } from "react-chartjs-2";

ChartJS.register(
  ArcElement,
  Tooltip,
  Legend,
  LineElement,
  CategoryScale,
  LinearScale,
  PointElement
);

function App() {
  const BASE_URL = "http://127.0.0.1:8000/api";

  const [expenses, setExpenses] = useState([]);
  const [title, setTitle] = useState("");
  const [amount, setAmount] = useState("");
  const [category, setCategory] = useState("Food");
  const [filter, setFilter] = useState("All");
  const [date, setDate] = useState("");

  const [error, setError] = useState(null);

  // AUTH
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [token, setToken] = useState(localStorage.getItem("token"));
  const [isRegister, setIsRegister] = useState(false);

  // LOGIN
  const handleLogin = async (e) => {
    e.preventDefault();
    setError(null);

    try {
      const res = await axios.post(`${BASE_URL}/token/`, {
        username,
        password,
      });

      localStorage.setItem("token", res.data.access);
      setToken(res.data.access);
    } catch {
      setError("Invalid credentials");
    }
  };

  // REGISTER
  const handleRegister = async (e) => {
    e.preventDefault();
    setError(null);

    try {
      await axios.post(`${BASE_URL}/register/`, {
        username,
        password,
      });

      alert("Registration successful. Please login.");
      setIsRegister(false);
    } catch {
      setError("Registration failed");
    }
  };

  // LOGOUT
  const handleLogout = () => {
    localStorage.removeItem("token");
    setToken(null);
    setUsername("");
    setPassword("");
  };

  // FETCH
  const fetchExpenses = useCallback(async () => {
    try {
      const res = await axios.get(`${BASE_URL}/expenses/`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });
      setExpenses(res.data);
    } catch (err) {
      if (err.response?.status === 401) {
        handleLogout();
      }
    }
  }, [token, BASE_URL]);

  useEffect(() => {
    if (token) fetchExpenses();
  }, [token, fetchExpenses]);

  // ADD
  const addExpense = async (e) => {
    e.preventDefault();

    try {
      await axios.post(
        `${BASE_URL}/expenses/`,
        {
          title,
          amount: Number(amount),
          category,
          date,
        },
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      setTitle("");
      setAmount("");
      setDate("");
      fetchExpenses();
    } catch {
      setError("Add failed");
    }
  };

  // DELETE
  const deleteExpense = async (id) => {
    try {
      await axios.delete(`${BASE_URL}/expenses/${id}/`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });
      fetchExpenses();
    } catch {
      setError("Delete failed");
    }
  };

  // TOTAL
  const total = useMemo(() => {
    return expenses.reduce((sum, exp) => sum + Number(exp.amount), 0);
  }, [expenses]);

  // MONTHLY TOTAL
  const monthlyTotal = useMemo(() => {
    const currentMonth = new Date().getMonth();

    return expenses
      .filter(
        (exp) =>
          exp.date &&
          new Date(exp.date).getMonth() === currentMonth
      )
      .reduce((sum, exp) => sum + Number(exp.amount), 0);
  }, [expenses]);

  // FILTER
  const filteredExpenses =
    filter === "All"
      ? expenses
      : expenses.filter((exp) => exp.category === filter);

  // PIE CHART
  const chartData = useMemo(() => {
    const data = {};
    expenses.forEach((exp) => {
      data[exp.category] =
        (data[exp.category] || 0) + Number(exp.amount);
    });

    return {
      labels: Object.keys(data),
      datasets: [{ data: Object.values(data) }],
    };
  }, [expenses]);

  // LINE CHART
  const lineData = useMemo(() => {
    const dailyData = {};

    expenses.forEach((exp) => {
      if (!exp.date) return;

      const day = new Date(exp.date).getDate();
      dailyData[day] = (dailyData[day] || 0) + Number(exp.amount);
    });

    const sortedDays = Object.keys(dailyData).sort((a, b) => a - b);

    return {
      labels: sortedDays,
      datasets: [
        {
          label: "Daily Expenses",
          data: sortedDays.map((day) => dailyData[day]),
        },
      ],
    };
  }, [expenses]);

  // LOGIN SCREEN
  if (!token) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 flex items-center justify-center">
        <div className="bg-white p-8 rounded-lg shadow-lg w-full max-w-md">
          <h2 className="text-2xl font-bold text-center mb-6 text-gray-800">
            {isRegister ? "Register" : "Login"}
          </h2>

          {error && (
            <p className="text-red-500 text-center mb-4 bg-red-50 p-2 rounded">
              {error}
            </p>
          )}

          <form onSubmit={isRegister ? handleRegister : handleLogin} className="space-y-4">
            <input
              placeholder="Username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            />

            <input
              type="password"
              placeholder="Password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            />

            <button
              type="submit"
              className="w-full bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700 transition duration-200"
            >
              {isRegister ? "Register" : "Login"}
            </button>
          </form>

          <br />

          <button
            onClick={() => setIsRegister(!isRegister)}
            className="w-full text-blue-600 hover:text-blue-800 transition duration-200"
          >
            {isRegister
              ? "Already have account? Login"
              : "Create new account"}
          </button>
        </div>
      </div>
    );
  }

  // MAIN APP
  return (
    <div style={{ padding: "20px", maxWidth: "600px", margin: "auto" }}>
      <h2>Expense Tracker</h2>

      <button onClick={handleLogout}>Logout</button>

      {error && <p style={{ color: "red" }}>{error}</p>}

      <form onSubmit={addExpense}>
        <input
          placeholder="Title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
        />

        <input
          type="number"
          placeholder="Amount"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
        />

        <select
          value={category}
          onChange={(e) => setCategory(e.target.value)}
        >
          <option>Food</option>
          <option>Travel</option>
          <option>Shopping</option>
        </select>

        <input
          type="date"
          value={date}
          onChange={(e) => setDate(e.target.value)}
        />

        <button>Add</button>
      </form>

      <h3>Total: ₹{total}</h3>
      <h4>This Month: ₹{monthlyTotal}</h4>

      {expenses.length > 0 && (
        <>
          <div style={{ width: "300px", margin: "auto" }}>
            <Pie data={chartData} />
          </div>

          <h3>Daily Trend</h3>
          <div style={{ width: "400px", margin: "auto" }}>
            <Line data={lineData} />
          </div>
        </>
      )}

      <select onChange={(e) => setFilter(e.target.value)}>
        <option>All</option>
        <option>Food</option>
        <option>Travel</option>
        <option>Shopping</option>
      </select>

      {filteredExpenses.map((exp) => (
        <div key={exp.id}>
          {exp.title} - ₹{exp.amount} ({exp.category}) - {exp.date}
          <button onClick={() => deleteExpense(exp.id)}>Delete</button>
        </div>
      ))}
    </div>
  );
}

export default App;
